sp_widget.client_script:
api.controller = function() {
  var c = this;
  c.data = c.data || {};

  c.createComplaint = function() {
    window.location.href = '?id=x_2091449_manage_0_create_complaint';
  };

  c.trackComplaint = function() {
    window.location.href = '?id=x_2091449_manage_0_track';
  };
};

sp_widget.css:
.sp-hero {
  background: linear-gradient(135deg, lighten($brand-primary, 30%) 0%, lighten($brand-primary, 15%) 50%, $brand-primary 100%);
  border-radius: $border-radius-large;
  margin-bottom: 24px;
  overflow: hidden;
  position: relative;
  &::after {
    content: '';
    position: absolute;
    inset: 0;
    background: rgba($btn-primary-color, 0.15);
    pointer-events: none;
  }
}
.sp-hero-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 48px;
  position: relative;
  z-index: 1;
  flex-wrap: wrap;
  gap: 24px;
}
.sp-hero-title {
  font-size: 32px;
  font-weight: 700;
  color: $btn-primary-color;
  margin: 0 0 8px;
  line-height: 1.2;
}
.sp-hero-subtitle {
  font-size: $font-size-base;
  color: $btn-primary-color;
  opacity: 0.85;
  margin: 0;
  max-width: 560px;
}
.sp-hero-actions {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
}
.sp-hero-btn {
  background: rgba($btn-primary-color, 0.9);
  color: $brand-primary;
  border: none;
  border-radius: $border-radius-base;
  height: 44px;
  padding: 0 20px;
  font-size: $font-size-base;
  font-weight: 500;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  transition: background 0.15s;
  &:hover {
    background: $btn-primary-color;
    color: $brand-primary-dark;
  }
}
.sp-hero-btn-secondary {
  background: rgba($btn-primary-color, 0.2);
  color: $btn-primary-color;
  border: 1px solid rgba($btn-primary-color, 0.4);
  border-radius: $border-radius-base;
  height: 44px;
  padding: 0 20px;
  font-size: $font-size-base;
  font-weight: 500;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  transition: background 0.15s;
  &:hover {
    background: rgba($btn-primary-color, 0.35);
    color: $btn-primary-color;
  }
}

sp_widget.script:
(function() {
  data.title = 'Consumer Case Portal';
  data.subtitle = 'Submit and track your complaints with ease. We are committed to resolving your issues quickly.';
  data.userName = '';
  data.isLoggedIn = false;

  try {
    var userId = gs.getUserID();
    if (userId && userId !== 'guest') {
      data.isLoggedIn = true;
      var userGr = new GlideRecord('sys_user');
      userGr.setLimit(1);
      if (userGr.get(userId)) {
        data.userName = userGr.getDisplayValue('first_name') + '';
      }
    }
  } catch (e) {
    gs.error('Home Hero widget error: ' + e.message);
  }
})();
